    flow1_t:'पूछताछ और स्पेक संरेखण', flow1_p:'हम खरीदार के सटीक उत्पाद विनिर्देशों, गुणवत्ता आवश्यकताओं, पैकिंग, गंतव्य और प्रमाणन प्राथमिकताओं की पुष्टि करते हैं।',
    flow2_t:'लॉट सोर्सिंग और प्री-निरीक्षण', flow2_p:'हम अपने विश्वसनीय आपूर्तिकर्ता नेटवर्क से उपयुक्त लॉट प्राप्त करते हैं और पेशकश करने से पहले गुणवत्ता को भौतिक रूप से सत्यापित करते हैं।',
    flow3_t:'अनुबंध संरक्षण', flow3_p:'हम स्वीकृत लॉट, सहमत स्पेक्स, शिपमेंट शर्तों और भुगतान शर्तों के आधार पर स्पष्ट अनुबंध तैयार करते हैं।',
    flow4_t:'कार्गो सत्यापन', flow4_p:'लोडिंग से पहले, प्रत्येक शिपमेंट की जांच स्वतंत्र निरीक्षण और हमारी आंतरिक गुणवत्ता समीक्षा के माध्यम से की जाती है।',
    flow5_t:'शिपमेंट और दावा सहायता', flow5_p:'हम दस्तावेज़ीकरण, लॉजिस्टिक्स, शिपमेंट फ़ॉलो-अप का प्रबंधन करते हैं और आवश्यकता पड़ने पर दावों के समन्वय का समर्थन करते हैं।',
    flow6_t:'बाजार खुफिया जानकारी', flow6_p:'हम ग्राहकों को सूचित खरीदारी निर्णय लेने में मदद करने के लिए नियमित बाजार अपडेट, मूल्य रुझान और आपूर्ति अंतर्दृष्टि साझा करते हैं।',
    edge_eyebrow:'Allnutts बढ़त', edge_h2:'Allnutts बढ़त', edge_p:'दुनिया के अग्रणी खरीदार हमारी सोर्सिंग बुद्धिमत्ता पर क्यों भरोसा करते हैं।',
    edge1_t:'दलाल, कारखाना नहीं', edge1_p:'हम वह नहीं बेचते जो हमारे पास है; हम वह ढूँढते हैं जो आपको चाहिए। हम खरीदार का प्रतिनिधित्व करते हैं, सही लॉट के लिए बाज़ार छानते हैं।',
    edge2_t:'गुणवत्ता कवच', edge2_p:'शून्य अस्पष्टता। हर लॉट जहाज़ लोडिंग से पहले स्वतंत्र तृतीय-पक्ष निरीक्षकों और हमारी अपनी आंतरिक गुणवत्ता टीम द्वारा जाँचा जाता है। हम सत्यापित करते हैं, फिर भेजते हैं।',
    edge3_t:'मूल खुफिया', edge3_p:'चेन्नई, कोल्लम और दोंग नाई में हमारी टीमों से रीयल-टाइम डेटा। हम मूल्य उतार-चढ़ाव से पहले अनुमान लगाते हैं।',
    edge4_t:'लॉजिस्टिक्स परिशुद्धता', edge4_p:'एंड-टू-एंड दस्तावेज़ प्रबंधन। बिल ऑफ़ लैडिंग से फाइटोसैनिटरी प्रमाणपत्र तक, हम शून्य बंदरगाह देरी सुनिश्चित करते हैं।',
    quote_eyebrow:'ट्रेडिंग डेस्क', quote_h2:'सीधा बाज़ार कोटेशन प्राप्त करें', quote_p:'हमारे विश्लेषक वर्तमान फसल उपज और मूल्य के आधार पर लक्षित प्रस्ताव देते हैं।',
    f_company:'पंजीकृत कंपनी का नाम', f_company_ph:'कंपनी लि.', f_product:'आवश्यक वस्तु',
    f_volume:'कुल मात्रा और शिपमेंट (जैसे 5x20 FCL)', f_volume_ph:'आवश्यक कुल मात्रा बताएँ',
    f_specs:'तकनीकी विशिष्टताएँ (ग्रेड, बंदरगाह, पैकिंग)', f_specs_ph:'उदाहरण: W320, 25 किग्रा वैक्यूम पैक, CIF वालेंसिया...',
    f_submit:'ट्रेडिंग डेस्क को भेजें', f_note:'आपका अनुरोध WhatsApp पर हमारे ट्रेडिंग डेस्क को एक पूर्व-भरा संदेश खोलता है।',
    opt_cashew:'काजू गिरी', opt_coffee:'रोबस्टा कॉफ़ी', opt_pepper:'काली मिर्च',
    about_eyebrow:'हमारा दर्शन', about_h2:'Allnutts दर्शन', about_p:'मूल खेतों और वैश्विक उद्योग के बीच पुल को परिभाषित करना।',
    about_legacy_t:'हमारी सोर्सिंग विरासत', about_legacy_p:'श्री पी.एस. प्रसाद द्वारा 1975 में स्थापित, हमारी यात्रा भारत की काजू राजधानी कोल्लम में स्थानीय कच्चे काजू (RCN) और काजू गिरी के व्यापार के साथ शुरू हुई। दशकों की गुणवत्ता प्रतिबद्धता, बाजार ज्ञान और संबंध-संचालित ब्रोकरेज पर निर्मित, हम वैश्विक बाजारों में संस्थागत खरीदारों की सेवा करने वाले एक विश्वसनीय सोर्सिंग हाउस बन गए हैं। प्रबंध निदेशक: ए. प्रसाद, एमबीए, एमएस',
